1943       if (Phi0->getIncomingBlock(Phi0Use) != Phi1->getIncomingBlock(Phi1Use))
1944         return false;
1945       Value *Phi0UseV = Phi0Use.get();
1946       Value *Phi1UseV = Phi1Use.get();
1947       if (Phi0UseV == C)
1948         NewIncomingValues.push_back(Phi1UseV);
1949       else if (Phi1UseV == C)
1950         NewIncomingValues.push_back(Phi0UseV);
1951       else
1952         return false;
1953       return true;
1954     };
1955 
1956     if (all_of(zip(Phi0->operands(), Phi1->operands()),
1957                CanFoldIncomingValuePair)) {
1958       PHINode *NewPhi =
1959           PHINode::Create(Phi0->getType(), Phi0->getNumOperands());
1960       assert(NewIncomingValues.size() == Phi0->getNumOperands() &&
1961              "The number of collected incoming values should equal the number "
1962              "of the original PHINode operands!");
1963       for (unsigned I = 0; I < Phi0->getNumOperands(); I++)
1964         NewPhi->addIncoming(NewIncomingValues[I], Phi0->getIncomingBlock(I));
1965       return NewPhi;
1966     }
1967   }
1968 
1969   if (Phi0->getNumOperands() != 2 || Phi1->getNumOperands() != 2)
1970     return nullptr;
1971 
1972   // Match a pair of incoming constants for one of the predecessor blocks.
1973   BasicBlock *ConstBB, *OtherBB;
1974   Constant *C0, *C1;
1975   if (match(Phi0->getIncomingValue(0), m_ImmConstant(C0))) {
1976     ConstBB = Phi0->getIncomingBlock(0);
1977     OtherBB = Phi0->getIncomingBlock(1);
1978   } else if (match(Phi0->getIncomingValue(1), m_ImmConstant(C0))) {
1979     ConstBB = Phi0->getIncomingBlock(1);
1980     OtherBB = Phi0->getIncomingBlock(0);
1981   } else {
1982     return nullptr;
1983   }
1984   if (!match(Phi1->getIncomingValueForBlock(ConstBB), m_ImmConstant(C1)))
1985     return nullptr;
1986 
1987   // The block that we are hoisting to must reach here unconditionally.
1988   // Otherwise, we could be speculatively executing an expensive or
1989   // non-speculative op.
1990   auto *PredBlockBranch = dyn_cast<BranchInst>(OtherBB->getTerminator());
1991   if (!PredBlockBranch || PredBlockBranch->isConditional() ||
1992       !DT.isReachableFromEntry(OtherBB))
1993     return nullptr;
1994 
1995   // TODO: This check could be tightened to only apply to binops (div/rem) that
1996   //       are not safe to speculatively execute. But that could allow hoisting
1997   //       potentially expensive instructions (fdiv for example).
1998   for (auto BBIter = BO.getParent()->begin(); &*BBIter != &BO; ++BBIter)
1999     if (!isGuaranteedToTransferExecutionToSuccessor(&*BBIter))
2000       return nullptr;
2001 
2002   // Fold constants for the predecessor block with constant incoming values.
2003   Constant *NewC = ConstantFoldBinaryOpOperands(BO.getOpcode(), C0, C1, DL);
2004   if (!NewC)
2005     return nullptr;
2006 
2007   // Make a new binop in the predecessor block with the non-constant incoming
2008   // values.
2009   Builder.SetInsertPoint(PredBlockBranch);
2010   Value *NewBO = Builder.CreateBinOp(BO.getOpcode(),
2011                                      Phi0->getIncomingValueForBlock(OtherBB),
2012                                      Phi1->getIncomingValueForBlock(OtherBB));
2013   if (auto *NotFoldedNewBO = dyn_cast<BinaryOperator>(NewBO))
2014     NotFoldedNewBO->copyIRFlags(&BO);
2015 
2016   // Replace the binop with a phi of the new values. The old phis are dead.
2017   PHINode *NewPhi = PHINode::Create(BO.getType(), 2);
2018   NewPhi->addIncoming(NewBO, OtherBB);
2019   NewPhi->addIncoming(NewC, ConstBB);
2020   return NewPhi;
2021 }
