2047 Instruction *InstCombinerImpl::foldVectorBinop(BinaryOperator &Inst) {
2048   if (!isa<VectorType>(Inst.getType()))
2049     return nullptr;
2050 
2051   BinaryOperator::BinaryOps Opcode = Inst.getOpcode();
2052   Value *LHS = Inst.getOperand(0), *RHS = Inst.getOperand(1);
2053   assert(cast<VectorType>(LHS->getType())->getElementCount() ==
2054          cast<VectorType>(Inst.getType())->getElementCount());
2055   assert(cast<VectorType>(RHS->getType())->getElementCount() ==
2056          cast<VectorType>(Inst.getType())->getElementCount());
2057 
2058   // If both operands of the binop are vector concatenations, then perform the
2059   // narrow binop on each pair of the source operands followed by concatenation
2060   // of the results.
2061   Value *L0, *L1, *R0, *R1;
2062   ArrayRef<int> Mask;
2063   if (match(LHS, m_Shuffle(m_Value(L0), m_Value(L1), m_Mask(Mask))) &&
2064       match(RHS, m_Shuffle(m_Value(R0), m_Value(R1), m_SpecificMask(Mask))) &&
2065       LHS->hasOneUse() && RHS->hasOneUse() &&
2066       cast<ShuffleVectorInst>(LHS)->isConcat() &&
2067       cast<ShuffleVectorInst>(RHS)->isConcat()) {
2068     // This transform does not have the speculative execution constraint as
2069     // below because the shuffle is a concatenation. The new binops are
2070     // operating on exactly the same elements as the existing binop.
2071     // TODO: We could ease the mask requirement to allow different undef lanes,
2072     //       but that requires an analysis of the binop-with-undef output value.
2073     Value *NewBO0 = Builder.CreateBinOp(Opcode, L0, R0);
2074     if (auto *BO = dyn_cast<BinaryOperator>(NewBO0))
2075       BO->copyIRFlags(&Inst);
2076     Value *NewBO1 = Builder.CreateBinOp(Opcode, L1, R1);
2077     if (auto *BO = dyn_cast<BinaryOperator>(NewBO1))
2078       BO->copyIRFlags(&Inst);
2079     return new ShuffleVectorInst(NewBO0, NewBO1, Mask);
2080   }
2081 
2082   auto createBinOpReverse = [&](Value *X, Value *Y) {
2083     Value *V = Builder.CreateBinOp(Opcode, X, Y, Inst.getName());
2084     if (auto *BO = dyn_cast<BinaryOperator>(V))
2085       BO->copyIRFlags(&Inst);
2086     Module *M = Inst.getModule();
2087     Function *F = Intrinsic::getOrInsertDeclaration(
2088         M, Intrinsic::vector_reverse, V->getType());
2089     return CallInst::Create(F, V);
2090   };
2091 
2092   // NOTE: Reverse shuffles don't require the speculative execution protection
2093   // below because they don't affect which lanes take part in the computation.
2094 
2095   Value *V1, *V2;
2096   if (match(LHS, m_VecReverse(m_Value(V1)))) {
2097     // Op(rev(V1), rev(V2)) -> rev(Op(V1, V2))
2098     if (match(RHS, m_VecReverse(m_Value(V2))) &&
2099         (LHS->hasOneUse() || RHS->hasOneUse() ||
2100          (LHS == RHS && LHS->hasNUses(2))))
2101       return createBinOpReverse(V1, V2);
2102 
2103     // Op(rev(V1), RHSSplat)) -> rev(Op(V1, RHSSplat))
2104     if (LHS->hasOneUse() && isSplatValue(RHS))
2105       return createBinOpReverse(V1, RHS);
2106   }
2107   // Op(LHSSplat, rev(V2)) -> rev(Op(LHSSplat, V2))
2108   else if (isSplatValue(LHS) && match(RHS, m_OneUse(m_VecReverse(m_Value(V2)))))
2109     return createBinOpReverse(LHS, V2);
2110 
2111   // It may not be safe to reorder shuffles and things like div, urem, etc.
2112   // because we may trap when executing those ops on unknown vector elements.
2113   // See PR20059.
2114   if (!isSafeToSpeculativelyExecuteWithVariableReplaced(&Inst))
2115     return nullptr;
2116 
2117   auto createBinOpShuffle = [&](Value *X, Value *Y, ArrayRef<int> M) {
2118     Value *XY = Builder.CreateBinOp(Opcode, X, Y);
2119     if (auto *BO = dyn_cast<BinaryOperator>(XY))
2120       BO->copyIRFlags(&Inst);
2121     return new ShuffleVectorInst(XY, M);
2122   };
2123 
2124   // If both arguments of the binary operation are shuffles that use the same
2125   // mask and shuffle within a single vector, move the shuffle after the binop.
2126   if (match(LHS, m_Shuffle(m_Value(V1), m_Poison(), m_Mask(Mask))) &&
2127       match(RHS, m_Shuffle(m_Value(V2), m_Poison(), m_SpecificMask(Mask))) &&
2128       V1->getType() == V2->getType() &&
2129       (LHS->hasOneUse() || RHS->hasOneUse() || LHS == RHS)) {
2130     // Op(shuffle(V1, Mask), shuffle(V2, Mask)) -> shuffle(Op(V1, V2), Mask)
2131     return createBinOpShuffle(V1, V2, Mask);
2132   }
2133 
2134   // If both arguments of a commutative binop are select-shuffles that use the
2135   // same mask with commuted operands, the shuffles are unnecessary.
2136   if (Inst.isCommutative() &&
2137       match(LHS, m_Shuffle(m_Value(V1), m_Value(V2), m_Mask(Mask))) &&
2138       match(RHS,
2139             m_Shuffle(m_Specific(V2), m_Specific(V1), m_SpecificMask(Mask)))) {
2140     auto *LShuf = cast<ShuffleVectorInst>(LHS);
2141     auto *RShuf = cast<ShuffleVectorInst>(RHS);
2142     // TODO: Allow shuffles that contain undefs in the mask?
2143     //       That is legal, but it reduces undef knowledge.
2144     // TODO: Allow arbitrary shuffles by shuffling after binop?
2145     //       That might be legal, but we have to deal with poison.
2146     if (LShuf->isSelect() &&
2147         !is_contained(LShuf->getShuffleMask(), PoisonMaskElem) &&
2148         RShuf->isSelect() &&
2149         !is_contained(RShuf->getShuffleMask(), PoisonMaskElem)) {
2150       // Example:
2151       // LHS = shuffle V1, V2, <0, 5, 6, 3>
2152       // RHS = shuffle V2, V1, <0, 5, 6, 3>
2153       // LHS + RHS --> (V10+V20, V21+V11, V22+V12, V13+V23) --> V1 + V2
2154       Instruction *NewBO = BinaryOperator::Create(Opcode, V1, V2);
2155       NewBO->copyIRFlags(&Inst);
2156       return NewBO;
2157     }
2158   }
2159 
2160   // If one argument is a shuffle within one vector and the other is a constant,
2161   // try moving the shuffle after the binary operation. This canonicalization
2162   // intends to move shuffles closer to other shuffles and binops closer to
2163   // other binops, so they can be folded. It may also enable demanded elements
2164   // transforms.
2165   Constant *C;
2166   auto *InstVTy = dyn_cast<FixedVectorType>(Inst.getType());
2167   if (InstVTy &&
2168       match(&Inst, m_c_BinOp(m_OneUse(m_Shuffle(m_Value(V1), m_Poison(),
2169                                                 m_Mask(Mask))),
2170                              m_ImmConstant(C))) &&
2171       cast<FixedVectorType>(V1->getType())->getNumElements() <=
2172           InstVTy->getNumElements()) {
2173     assert(InstVTy->getScalarType() == V1->getType()->getScalarType() &&
2174            "Shuffle should not change scalar type");
2175 
2176     // Find constant NewC that has property:
2177     //   shuffle(NewC, ShMask) = C
2178     // If such constant does not exist (example: ShMask=<0,0> and C=<1,2>)
2179     // reorder is not possible. A 1-to-1 mapping is not required. Example:
2180     // ShMask = <1,1,2,2> and C = <5,5,6,6> --> NewC = <undef,5,6,undef>
2181     bool ConstOp1 = isa<Constant>(RHS);
2182     ArrayRef<int> ShMask = Mask;
2183     unsigned SrcVecNumElts =
2184         cast<FixedVectorType>(V1->getType())->getNumElements();
2185     PoisonValue *PoisonScalar = PoisonValue::get(C->getType()->getScalarType());
2186     SmallVector<Constant *, 16> NewVecC(SrcVecNumElts, PoisonScalar);
